CREATE OR REPLACE FUNCTION fpa_tel_get_shareamount (as_conno char) RETURNS bigint AS $body$
DECLARE

  ldc_return bigint;

BEGIN
  select  share_amount into STRICT ldc_return
  from    sc_mem_m_share_mem
  where   (membership_no =
          (
          SELECT  membership_no
          from    sc_lon_m_contract
          where (loan_contract_no =as_conno )
            ));
  RETURN ldc_return;
exception
when no_data_found then return null;
when others then CALL spa_dberror('FPA_TEL_GET_SHAREAMOUNT');return null;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
